// importDelete removes a pending or quarantined file (+ sidecar).
func importDelete(name string, from string) templ.ComponentScript {
	return templ.ComponentScript{
		Name: `__templ_importDelete_c87d`,
		Function: `function __templ_importDelete_c87d(name, from){if (!window.confirm('Delete ' + name + '?')) return;
	fetch('/api/v1/upload/' + encodeURIComponent(name) + '?from=' + from, {
		method: 'DELETE',
		headers: { 'X-Blittermib-Upload': '1' },
	})
		.then(function (resp) {
			if (resp.status === 204) {
				window.location.reload();
				return;
			}
			window.alert('Delete failed: HTTP ' + resp.status);
		})
		.catch(function (err) {
			window.alert('Delete failed: ' + err);
		});
}`,
		Call:       templ.SafeScript(`__templ_importDelete_c87d`, name, from),
		CallInline: templ.SafeScriptInline(`__templ_importDelete_c87d`, name, from),
	}
}

